// formatComment applies basic formatting to comment text.
// It first escapes HTML via the template engine (since we pass through template.HTML after manual escaping),
// then applies **bold**, _italic_, and `code` formatting.
func formatComment(content string) template.HTML {
	// First, manually escape HTML special characters to prevent XSS
	escaped := template.HTMLEscapeString(content)

	// Apply basic formatting rules on the escaped content

	// Bold: **text**
	escaped = applyFormatting(escaped, "**", "<strong>", "</strong>")

	// Italic: _text_
	escaped = applyFormatting(escaped, "_", "<em>", "</em>")

	// Inline code: `text`
	escaped = applyFormatting(escaped, "`", "<code>", "</code>")

	// Convert newlines to <br>
	escaped = strings.ReplaceAll(escaped, "\n", "<br>")

	return template.HTML(escaped)
}

// applyFormatting finds pairs of delimiters and wraps content in HTML tags
func applyFormatting(text, delimiter, openTag, closeTag string) string {
	var result strings.Builder
	remaining := text

	for {
		// Find the first delimiter
		startIdx := strings.Index(remaining, delimiter)
		if startIdx == -1 {
			result.WriteString(remaining)
			break
		}

		// Find the closing delimiter
		endIdx := strings.Index(remaining[startIdx+len(delimiter):], delimiter)
		if endIdx == -1 {
			result.WriteString(remaining)
			break
		}

		// Calculate actual end index relative to remaining
		endIdx = startIdx + len(delimiter) + endIdx

		// Write everything before the opening delimiter
		result.WriteString(remaining[:startIdx])

		// Write the formatted content
		innerContent := remaining[startIdx+len(delimiter) : endIdx]
		if innerContent != "" {
			result.WriteString(openTag)
			result.WriteString(innerContent)
			result.WriteString(closeTag)
		} else {
			// Empty content between delimiters, keep delimiters as-is
			result.WriteString(delimiter)
			result.WriteString(delimiter)
		}

		// Move past the closing delimiter
		remaining = remaining[endIdx+len(delimiter):]
	}

	return result.String()
}

